INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '36aa54c8-de31-40c9-bcbf-7c3c4c7f0a3a',
  '00000000-0000-0000-0000-000000000001',
  $escape$csharp_game Hot Reloading — Efficient Script Reloading with Minimal Recompilation$escape$,
  $escape$csharp_game developers can leverage hot reloading to apply live code changes without requiring a full recompile. This is achieved by utilizing the `AssemblyReload` API, which enables the reloading of modified scripts. By implementing the `IHotReloadable` interface, scripts can be reloaded efficiently, minimizing the need for a full recompile. This approach significantly streamlines the development process, allowing for rapid iteration and testing. To optimize hot reloading, focus on script organization and utilize the `#if DEBUG` directive to ensure seamless reloads.$escape$,
  $escape$#if DEBUG
using csharp_game.Assets;
using csharp_game.Core;
public class MyScript : IHotReloadable {
    public void OnReload() {
        // Handle script reload logic
    }
}$escape$,
  $escape$csharp$escape$,
