INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'acb98c6c-d13d-4c65-add9-82b2445194e9',
  '00000000-0000-0000-0000-000000000001',
  $escape$csharp_game Performance Optimization: Reducing GC Pressure with Object Pooling$escape$,
  $escape$To minimize garbage collection (GC) pressure in csharp_game, developers can leverage object pooling. This technique involves reusing existing objects instead of constantly allocating and deallocating new ones. By reducing mid-frame allocations, object pooling helps maintain a stable frame rate and improves overall game performance. csharp_game's built-in `ObjectPool<T>` class can be utilized to implement object pooling. Additionally, avoiding unnecessary allocations within performance-critical code paths, such as Update() and FixedUpdate() methods, is crucial for optimal performance.$escape$,
  $escape$public class GameObjectPool : ObjectPool<GameObject> { public GameObjectPool(int initialSize) : base(initialSize) {} public GameObject GetPooledObject() { return GetObject(); } }$escape$,
  $escape$csharp$escape$,
