INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '48ba84c8-bb0f-4092-9a56-b4837c2ca1f4',
  '00000000-0000-0000-0000-000000000001',
  $escape$csharp_game: Integrating Native C# Plugins in Unity$escape$,
  $escape$When working with csharp_game in Unity, integrating native C# plugins can significantly enhance performance and functionality. Unity's API allows for seamless interaction between C# and native code. By utilizing the `DllImport` attribute, developers can import native libraries and access their functionality within C# scripts. This enables the use of high-performance, native code for tasks such as physics simulations or graphics rendering, while still leveraging the ease of use and rapid development of C#. Additionally, Unity's `IntPtr` type facilitates the passing of native pointers to C# functions, further bridging the gap between managed and unmanaged code.$escape$,
  $escape$using System.Runtime.InteropServices; [DllImport("MyNativeLibrary")]
public static extern int MyNativeFunction(int x, int y);$escape$,
